/*
 * ceil() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly ceil  (test_ceil_opt.elf)
 *   2. Linked with toolchain's default ceil        (test_ceil_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += ceil(vx);
#else
    double r = ceil(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* test_representative_100: 100 representative inputs for ceil()      */
/* ------------------------------------------------------------------ */

#ifndef EN_PERF
static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(DBL_MIN);                  /* 2^-1022, smallest normal */
    emit(-DBL_MIN);
    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    emit(DBL_MAX);                  /* largest finite double */
    emit(-DBL_MAX);
    emit_u(0x7fefffffffffffffULL);  /* DBL_MAX itself (same as above via u) - use one ULP below */

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    emit(1.0);
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    emit_u(0x3feffffffffffffeULL);  /* two ULPs below 1.0 */
    emit_u(0x3ff0000000000002ULL);  /* two ULPs above 1.0 */
    emit(-1.0);
    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exact integers positive and negative (10) --- */
    emit(2.0);
    emit(3.0);
    emit(4.0);
    emit(5.0);
    emit(100.0);
    emit(-2.0);
    emit(-3.0);
    emit(-4.0);
    emit(-5.0);
    emit(-100.0);

    /* --- Section 6: Half-integer values n+0.5 (10) --- */
    emit(0.5);
    emit(1.5);
    emit(2.5);
    emit(3.5);
    emit(10.5);
    emit(-0.5);
    emit(-1.5);
    emit(-2.5);
    emit(-3.5);
    emit(-10.5);

    /* --- Section 7: ULP neighbors of exact integers (12) --- */
    emit_u(0x3fefffffffffffffULL);  /* largest double < 1.0: ceil -> 1.0 */
    emit_u(0x3ff0000000000001ULL);  /* just above 1.0: ceil -> 2.0 */
    emit_u(0x400fffffffffffffULL);  /* just below 4.0 (ULP): ceil -> 4.0 */
    emit_u(0x4010000000000001ULL);  /* just above 4.0: ceil -> 5.0 */
    emit_u(0xbfefffffffffffffULL);  /* just above -1.0 (toward 0): ceil -> 0.0 */
    emit_u(0xbff0000000000001ULL);  /* just below -1.0 (away from 0): ceil -> -1.0 */
    emit_u(0x4340000000000000ULL);  /* 2^53: exact integer, no fractional bits */
    emit_u(0x433fffffffffffffULL);  /* one ULP below 2^53: has fractional part */
    emit_u(0xc340000000000000ULL);  /* -2^53: exact integer */
    emit_u(0xc33fffffffffffffULL);  /* one ULP above -2^53 (toward 0): has fractional part */
    emit_u(0x3ff0000000000000ULL);  /* exactly 1.0 again (boundary confirm) */
    emit_u(0xbff0000000000000ULL);  /* exactly -1.0 again */

    /* --- Section 8: Fractional inputs with various tenths (16) --- */
    emit(0.1);
    emit(0.2);
    emit(0.3);
    emit(0.4);
    emit(0.6);
    emit(0.7);
    emit(0.8);
    emit(0.9);
    emit(-0.1);
    emit(-0.2);
    emit(-0.3);
    emit(-0.4);
    emit(-0.6);
    emit(-0.7);
    emit(-0.8);
    emit(-0.9);

    /* --- Section 9: Large values where double has no fractional bits (10) --- */
    emit(1.0e15);       /* within integer-exact range of double */
    emit(-1.0e15);
    emit(1.0e16);       /* still exactly representable as integer */
    emit(-1.0e16);
    emit(1.0e100);      /* very large: already an integer */
    emit(-1.0e100);
    emit(1.0e300);
    emit(-1.0e300);
    emit_u(0x4330000000000000ULL);  /* 2^52: smallest double >= 2^52 with no frac bits */
    emit_u(0xc330000000000000ULL);  /* -2^52 */

    /* --- Section 10: Near-zero and tiny positive/negative (15) --- */
    emit(1.0e-10);
    emit(-1.0e-10);
    emit(1.0e-100);
    emit(-1.0e-100);
    emit(1.0e-200);
    emit(-1.0e-200);
    emit(0.0000000000001);   /* tiny positive: ceil -> 1.0 */
    emit(-0.0000000000001);  /* tiny negative: ceil -> 0.0 */
    emit(0.4999999999999);   /* just below 0.5: ceil -> 1.0 */
    emit(0.5000000000001);   /* just above 0.5: ceil -> 1.0 */
    emit(-0.4999999999999);  /* just above -0.5: ceil -> 0.0 */
    emit(-0.5000000000001);  /* just below -0.5: ceil -> 0.0 */
    emit(0.9999999999999);   /* just below 1.0: ceil -> 1.0 */
    emit(1.0000000000001);   /* just above 1.0: ceil -> 2.0 */
    emit(-0.9999999999999);  /* just above -1.0: ceil -> 0.0 */
}
#endif /* !EN_PERF */

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(double x)
{
    volatile double acc = 0.0;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += ceil(x+i);
    stopPFM;
    readResult();
    printf("perf %016llx: %016llx\n",
           (unsigned long long)d2u(x),
           (unsigned long long)d2u((double)acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* 7. Sweep [0, 10] in 100 steps and [-10, 0] in 100 steps */
static void test_sweep(void)
{
    double hi = 10.0;
    int nsteps = 100;
    double step = hi / (double)nsteps;

    /* [0, 10] */
    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);

    /* [-10, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (double)i * step);
}

/* 8. Sample [0, 10] every ~0.05 (200 points) */
static void test_exhaustive_small(void)
{
    double hi = 10.0;
    int nsteps = 200;
    double step = hi / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);
}
#endif /* !EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

