    emit_u(0xc350000000000000ULL);  /* -2^54 */

    /* --- Section 10: Near-zero and tiny positive/negative (15) --- */
    emit(1.0e-10);
    emit(-1.0e-10);
    emit(1.0e-100);
    emit(-1.0e-100);
    emit(1.0e-200);
    emit(-1.0e-200);
    emit(0.0000000000001);   /* tiny positive: ceil -> 1.0 */
    emit(-0.0000000000001);  /* tiny negative: ceil -> 0.0 */
    emit(0.4999999999999);   /* just below 0.5: ceil -> 1.0 */
    emit(0.5000000000001);   /* just above 0.5: ceil -> 1.0 */
    emit(-0.4999999999999);  /* just above -0.5 toward zero: ceil -> 0.0 */
    emit(-0.5000000000001);  /* just below -0.5 away from zero: ceil -> 0.0 */
    emit(0.9999999999999);   /* just below 1.0: ceil -> 1.0 */
    emit(1.0000000000001);   /* just above 1.0: ceil -> 2.0 */
    emit(-0.9999999999999);  /* just above -1.0 toward zero: ceil -> 0.0 */
}

